const k = kaplay({
    canvas: document.getElementById("kaplay-bg"),
    background: [0, 0, 0, 0],
});

let mouse = vec2(0, 0);

window.addEventListener("mousemove", (e) => {
    mouse = vec2(e.clientX, e.clientY);
});


import kaplay from "data:text/javascript;base64,";
 // virtual:/main.js

loadSprite("bean", "data:image/png;base64,");
loadSprite("beant", "data:image/png;base64,");
loadSprite("zombean", "data:image/png;base64,");
loadBitmapFont("monospace", "data:image/png;base64,", 36, 45);
var beans = [
  // lerpAngle() clamps angle to go from 180 to -180 the shorter path
  ["bean", "lerpAngle"],
  // lerp() will go the long way around from 180 to -180, doing 360 spin
  ["beant", "lerp"],
  // workaround using Vec2 spherical lerp, but with a lot of conversions
  ["zombean", function workaround(a, b, t) {
    return Vec2.fromAngle(a).slerp(Vec2.fromAngle(b), t).angle();
  }]
].map(
  ([spriteName, lerpMethod], i, a) => add([
    anchor("center"),
    sprite(spriteName),
    pos(center().add(-220 * (a.length - 1) / 2 + 220 * i, 0)),
    rotate(0),
    fixed(),
    scale(3),
    {
      toAngle: null,
      lerpMethod: k[lerpMethod] || lerpMethod,
      txt: typeof lerpMethod === "string" ? lerpMethod + (!k[lerpMethod] ? "\nunsupported" : "") : lerpMethod.name || "customFn",
      
      update() {
        const toAngle = mouse.sub(this.pos).angle();

  if (this.toAngle === null && Math.abs(toAngle) > 90) {
    this.flipY = true;
    this.angle = -180;
  }

  this.toAngle = toAngle;

  if (typeof this.lerpMethod !== "function") return;

  this.angle = this.lerpMethod(this.angle, this.toAngle, 0.12);
  this.flipY = Math.abs(this.angle) > 90;
        if (this.toAngle === null) return;
        if (typeof this.lerpMethod !== "function") return;
        this.angle = this.lerpMethod(this.angle, this.toAngle, 0.12);
        this.flipY = Math.abs(this.angle) > 90;
      }
    }
  ])
);
onDraw(
  () => beans.forEach(
    (b) => drawText({
      text: b.txt,
      size: 28,
      align: "center",
      anchor: "top",
      pos: b.pos.add(0, 100),
      letterSpacing: -4,
      width: b.width * b.scale.x + 24
    })
  )
);


